#include<bits/stdc++.h>
using namespace std;

long long dp[300005][20];
long long t,m,s,ans=0;
int main(){
    cin>>m>>s>>t;
    while(m>=10&&s>=60&&t>=1){
        m-=10;
        s-=60;
        t--;
        ans++;
    }
    if(m>=10&&s<=60&&t>=1){
        cout<<"Yes\n"<<ans+1;
        return 0;
    }
    if(t<=0){
        cout<<"No";
        cout<<"\n"<<ans*60;
        return 0;
    }
    fill(dp[0], dp[0] + 100005 * 20, LLONG_MIN / 1000);
    dp[0][m]=0;
    for(int i=0;i<=t;i++){
        for(int j=0;j<=14;j++){
            if(dp[i][j]>=s){
                cout<<"Yes\n";
                cout<<ans+i;
                return 0;
            }
            if(j>=10&&i<t) dp[i+1][j-10]=max(dp[i+1][j-10],dp[i][j]+60);
            if(j<=10&&i<t) dp[i+1][j+4]=max(dp[i+1][j+4],dp[i][j]);
            dp[i+1][j]=max(dp[i+1][j],dp[i][j]+17);
        }
    }
    cout<<"No";
    long long anns=LLONG_MIN/1000;
    for(int i=0;i<=14;i++) anns=max(anns,dp[t][i]);
    cout<<"\n"<<anns+ans*60;
    return 0;
}
